import { expect, test } from "@repo/testing/e2e";
import { WaitUtils } from "@repo/testing/e2e";

test.describe("Error Handling", () => {
  let waitUtils: WaitUtils;

  test.beforeEach(async ({ page }) => {
    waitUtils = new WaitUtils(page);
  });

  test("should show 404 page for non-existent routes", async ({ page }) => {
    const response = await page.goto("/non-existent-page-12345");

    // Should return 404 status
    expect(response?.status()).toBe(404);

    // Should show custom 404 page
    const pageContent = await page.textContent("body");
    expect(pageContent).toMatch(/404|not found|page not found/i);

    // Should have a way to navigate back
    const homeLink = page.getByRole("link", { name: /home|back|return/i });
    if ((await homeLink.count()) > 0) {
      await expect(homeLink.first()).toBeVisible();
    }
  });

  test("should handle deep non-existent nested routes", async ({ page }) => {
    const response = await page.goto(
      "/products/non-existent-product/deep/nested/path",
    );

    expect(response?.status()).toBe(404);

    const pageContent = await page.textContent("body");
    expect(pageContent).toMatch(/404|not found|page not found/i);
  });

  test("should handle non-existent dynamic routes", async ({ page }) => {
    const testRoutes = [
      "/products/non-existent-product-xyz",
      "/collections/non-existent-collection-xyz",
      "/blog/non-existent-post-xyz",
      "/users/non-existent-user-xyz",
    ];

    for (const route of testRoutes) {
      const response = await page.goto(route);
      expect(response?.status()).toBe(404);

      const pageContent = await page.textContent("body");
      expect(pageContent).toMatch(/404|not found|page not found/i);
    }
  });

  test("should have proper error page layout", async ({ page }) => {
    await page.goto("/non-existent-page-12345");

    // Should have title
    const title = await page.title();
    expect(title).toMatch(/404|not found/i);

    // Should have proper heading
    const heading = page.getByRole("heading").first();
    if ((await heading.count()) > 0) {
      const headingText = await heading.textContent();
      expect(headingText).toMatch(/404|not found/i);
    }

    // Should have navigation
    const navigation = page.getByRole("navigation");
    if ((await navigation.count()) > 0) {
      await expect(navigation.first()).toBeVisible();
    }
  });

  test("should handle JavaScript errors gracefully", async ({ page }) => {
    const _errors: Error[] = [];

    page.on("pageerror", (error) => {
      _errors.push(error);
    });

    page.on("console", (msg) => {
      if (msg.type() === "error") {
        console.log("Console error:", msg.text());
      }
    });

    await page.goto("/");
    await waitUtils.forNavigation();

    // Inject a JavaScript error
    await page.evaluate(() => {
      try {
        // @ts-ignore - intentional error
        undefinedFunction();
      } catch (_e) {
        // Error should be caught and handled
      }
    });

    // Page should still be functional
    const pageContent = await page.textContent("body");
    expect(pageContent).toBeTruthy();
  });

  test("should handle network errors gracefully", async ({ page }) => {
    // Start with a valid page
    await page.goto("/");
    await waitUtils.forNavigation();

    // Simulate network failure
    await page.route("**/*", (route) => {
      if (route.request().url().includes("api/")) {
        route.abort("failed");
      } else {
        route.continue();
      }
    });

    // Try to make an API call
    const apiCall = page.evaluate(async () => {
      try {
        const response = await fetch("/api/health");
        return response.ok;
      } catch (_error) {
        return false;
      }
    });

    const result = await apiCall;
    expect(result).toBe(false);

    // Page should still be responsive
    const body = page.locator("body");
    await expect(body).toBeVisible();
  });

  test("should show error boundaries for React errors", async ({ page }) => {
    await page.goto("/");
    await waitUtils.forNavigation();

    // Try to trigger a React error
    await page.evaluate(() => {
      // Dispatch a custom event that might trigger an error
      window.dispatchEvent(new CustomEvent("test-error"));
    });

    // Page should still be functional
    const isPageFunctional = await page.evaluate(() => {
      return (
        document.body &&
        document.body.textContent &&
        document.body.textContent.length > 0
      );
    });

    expect(isPageFunctional).toBeTruthy();
  });

  test("should handle form submission errors", async ({ page }) => {
    await page.goto("/");
    await waitUtils.forNavigation();

    // Look for forms
    const form = page.locator("form").first();

    if ((await form.count()) > 0) {
      // Try to submit empty form
      const submitButton = form.getByRole("button", {
        name: /submit|send|save/i,
      });

      if ((await submitButton.count()) > 0) {
        await submitButton.click();
        await page.waitForTimeout(1000);

        // Should show validation errors or handle gracefully
        const errorMessages = page.locator(
          '.error, [role="alert"], .alert-error',
        );
        const hasErrors = (await errorMessages.count()) > 0;

        // Either should show errors or page should remain functional
        if (!hasErrors) {
          const pageContent = await page.textContent("body");
          expect(pageContent).toBeTruthy();
        }
      }
    }
  });

  test("should handle search with no results", async ({ page }) => {
    await page.goto("/");
    await waitUtils.forNavigation();

    // Look for search functionality
    const searchInput = page.getByRole("searchbox");

    if ((await searchInput.count()) > 0) {
      await searchInput.fill("xyznonexistentquerythatshouldhavenoResults123");
      await page.keyboard.press("Enter");
      await waitUtils.forNavigation();

      // Should show "no results" message
      const noResults = page.getByText(
        /no results|not found|no matches|nothing found/i,
      );
      if ((await noResults.count()) > 0) {
        await expect(noResults.first()).toBeVisible();
      }

      // Should have a way to go back or try again
      const backLink = page.getByRole("link", { name: /back|home|try again/i });
      if ((await backLink.count()) > 0) {
        await expect(backLink.first()).toBeVisible();
      }
    }
  });

  test("should handle expired sessions gracefully", async ({ page }) => {
    // This would be more relevant for authenticated areas
    await page.goto("/account");

    // Should either redirect to login or show appropriate message
    const currentUrl = page.url();
    const isAuthRoute =
      currentUrl.includes("/login") ||
      currentUrl.includes("/signin") ||
      currentUrl.includes("/auth");
    const hasAuthMessage =
      (await page.getByText(/sign in|login|authenticate/i).count()) > 0;

    // Either should redirect to auth or show auth prompt
    expect(isAuthRoute || hasAuthMessage).toBeTruthy();
  });

  test("should handle large payloads gracefully", async ({ page }) => {
    await page.goto("/");
    await waitUtils.forNavigation();

    // Try to submit a very large form data
    const largeString = "x".repeat(100000); // 100KB string

    const result = await page.evaluate(async (data) => {
      try {
        const formData = new FormData();
        formData.append("large_field", data);

        const response = await fetch("/api/test-endpoint", {
          body: formData,
          method: "POST",
        });

        return { status: response.status, success: true };
      } catch (error) {
        return { error: (error as Error).message, success: false };
      }
    }, largeString);

    // Should handle large payloads (success or proper error)
    expect(result).toBeTruthy();
  });

  test("should have proper error page SEO", async ({ page }) => {
    const response = await page.goto("/non-existent-page-12345");
    expect(response?.status()).toBe(404);

    // Should have proper title
    const title = await page.title();
    expect(title).toBeTruthy();
    expect(title).toMatch(/404|not found/i);

    // Should have meta description
    const description = await page.getAttribute(
      'meta[name="description"]',
      "content",
    );
    if (description) {
      expect(description).toMatch(/404|not found|page not found/i);
    }

    // Should not be indexed
    const robotsMeta = await page.getAttribute(
      'meta[name="robots"]',
      "content",
    );
    if (robotsMeta) {
      expect(robotsMeta).toMatch(/noindex/i);
    }
  });

  test("should handle slow loading gracefully", async ({ page }) => {
    // Throttle network to simulate slow connection
    const client = await page.context().newCDPSession(page);
    await client.send("Network.emulateNetworkConditions", {
      downloadThroughput: 50 * 1024, // 50 KB/s
      latency: 2000, // 2 second delay
      offline: false,
      uploadThroughput: 50 * 1024,
    });

    const startTime = Date.now();
    await page.goto("/");

    // Should show loading state or handle gracefully
    const loadTime = Date.now() - startTime;

    // Page should eventually load even with slow network
    const pageContent = await page.textContent("body");
    expect(pageContent).toBeTruthy();

    // Should handle the slow loading (showing loaders, etc.)
    expect(loadTime).toBeGreaterThan(1000); // Should take some time due to throttling
  });

  test("should handle malformed URLs", async ({ page }) => {
    const malformedUrls = [
      "/products/%",
      "/collections/%%invalid%%",
      '/blog/<script>alert("xss")</script>',
      "/users/../../etc/passwd",
    ];

    for (const url of malformedUrls) {
      try {
        const response = await page.goto(url);

        // Should handle gracefully (404 or redirect)
        expect(response?.status()).toBeLessThan(500);

        const pageContent = await page.textContent("body");
        expect(pageContent).toBeTruthy();

        // Should not execute scripts or expose system files
        expect(pageContent).not.toContain("<script>");
        expect(pageContent).not.toContain("etc/passwd");
      } catch (error) {
        // Some malformed URLs might throw network errors, which is acceptable
        expect((error as Error).message).toBeTruthy();
      }
    }
  });
});

import { expect, test } from "@repo/testing/e2e";
import { WaitUtils } from "@repo/testing/e2e";

test.describe("Navigation", () => {
  let waitUtils: WaitUtils;

  test.beforeEach(async ({ page }) => {
    waitUtils = new WaitUtils(page);
  });

  test("should navigate between main pages", async ({ page }) => {
    // Start at homepage
    await page.goto("/");
    await waitUtils.forNavigation();

    // Navigate to collections
    const collectionsLink = page.getByRole("link", { name: /collections/i });
    if ((await collectionsLink.count()) > 0) {
      await collectionsLink.first().click();
      await waitUtils.forNavigation();
      expect(page.url()).toContain("/collections");
    }

    // Navigate to about page
    await page.goto("/about");
    await waitUtils.forNavigation();
    const aboutHeading = page.getByRole("heading", { name: /about/i });
    if ((await aboutHeading.count()) > 0) {
      await expect(aboutHeading.first()).toBeVisible();
    }

    // Navigate to contact
    await page.goto("/contact");
    await waitUtils.forNavigation();
    expect(page.url()).toContain("/contact");
  });

  test("should handle product navigation", async ({ page }) => {
    await page.goto("/");
    await waitUtils.forNavigation();

    // Look for product cards
    const productCard = page.locator('[data-testid="product-card"]').first();
    const productLink = page
      .getByRole("link")
      .filter({ hasText: /product|shop/i })
      .first();

    if ((await productCard.count()) > 0) {
      await productCard.click();
      await waitUtils.forNavigation();
      expect(page.url()).toMatch(/\/products?\//);
    } else if ((await productLink.count()) > 0) {
      await productLink.click();
      await waitUtils.forNavigation();
      expect(page.url()).toMatch(/\/products?/);
    }
  });

  test("should handle cart navigation", async ({ page }) => {
    await page.goto("/");
    await waitUtils.forNavigation();

    // Look for cart icon or link
    const cartButton = page.getByRole("button", { name: /cart/i });
    const cartLink = page.getByRole("link", { name: /cart/i });

    if ((await cartButton.count()) > 0) {
      await cartButton.first().click();
      // Cart might be a modal or page
      await page.waitForTimeout(1000);
    } else if ((await cartLink.count()) > 0) {
      await cartLink.first().click();
      await waitUtils.forNavigation();
      expect(page.url()).toContain("/cart");
    }
  });

  test("should navigate to auth pages", async ({ page }) => {
    // Test sign in navigation
    await page.goto("/login");
    await waitUtils.forNavigation();
    expect(page.url()).toContain("/login");

    // Test sign up navigation
    await page.goto("/signup");
    await waitUtils.forNavigation();
    expect(page.url()).toContain("/signup");

    // Test forgot password navigation
    await page.goto("/forgot-password");
    await waitUtils.forNavigation();
    expect(page.url()).toContain("/forgot-password");
  });

  test("should handle account pages navigation", async ({ page }) => {
    const accountPages = [
      "/account",
      "/account-billing",
      "/account-password",
      "/account-wishlists",
      "/orders",
    ];

    for (const accountPage of accountPages) {
      await page.goto(accountPage);
      await waitUtils.forNavigation();
      // These pages might redirect if not authenticated
      expect(page.url()).toBeTruthy();
    }
  });

  test("should handle back navigation", async ({ page }) => {
    await page.goto("/");
    await waitUtils.forNavigation();

    await page.goto("/about");
    await waitUtils.forNavigation();

    await page.goBack();
    await waitUtils.forNavigation();
    expect(page.url()).toMatch(/\/$/); // Should be back at homepage
  });

  test("should have working header navigation", async ({ page }) => {
    await page.goto("/");
    await waitUtils.forNavigation();

    // Check for logo link
    const logo = page.getByRole("link", { name: /logo|home/i });
    if ((await logo.count()) > 0) {
      const currentUrl = page.url();
      await logo.first().click();
      await waitUtils.forNavigation();
      // Should stay on homepage or navigate to it
      expect(page.url()).toMatch(/\/$/);
    }
  });

  test("should handle search navigation", async ({ page }) => {
    await page.goto("/");
    await waitUtils.forNavigation();

    // Look for search input
    const searchInput = page.getByRole("searchbox");
    const searchButton = page.getByRole("button", { name: /search/i });

    if ((await searchInput.count()) > 0) {
      await searchInput.first().fill("test product");
      if ((await searchButton.count()) > 0) {
        await searchButton.first().click();
      } else {
        await searchInput.first().press("Enter");
      }
      await waitUtils.forNavigation();
      // Should navigate to search results
      expect(page.url()).toMatch(/search|q=/);
    }
  });

  test("should handle footer navigation", async ({ page }) => {
    await page.goto("/");
    await waitUtils.forNavigation();

    // Scroll to footer
    await page.evaluate(() => window.scrollTo(0, document.body.scrollHeight));
    await page.waitForTimeout(500);

    // Check for common footer links
    const footerLinks = [
      { url: "/about", text: /about/i },
      { url: "/contact", text: /contact/i },
      { url: "/blog", text: /blog/i },
    ];

    for (const link of footerLinks) {
      const footerLink = page.getByRole("link", { name: link.text });
      if ((await footerLink.count()) > 0) {
        const href = await footerLink.first().getAttribute("href");
        expect(href).toContain(link.url);
      }
    }
  });

  test("should handle breadcrumb navigation", async ({ page }) => {
    // Navigate to a product page
    await page.goto("/");
    await waitUtils.forNavigation();

    // Try to find a collection or product link
    const collectionLink = page
      .getByRole("link")
      .filter({ hasText: /collection|category/i })
      .first();
    if ((await collectionLink.count()) > 0) {
      await collectionLink.click();
      await waitUtils.forNavigation();

      // Check for breadcrumbs
      const breadcrumb = page.getByRole("navigation", { name: /breadcrumb/i });
      if ((await breadcrumb.count()) > 0) {
        const homeLink = breadcrumb.getByRole("link", { name: /home/i });
        if ((await homeLink.count()) > 0) {
          await homeLink.click();
          await waitUtils.forNavigation();
          expect(page.url()).toMatch(/\/$/);
        }
      }
    }
  });
});

/**
 * E2E tests for account/user pages
 */

import { expect, test } from "@repo/testing/e2e";
import {
  AccessibilityTestUtils,
  createAuthHelpers,
  ResponsiveTestUtils,
  VisualTestUtils,
  WaitUtils,
} from "@repo/testing/e2e";

import type { BetterAuthTestHelpers } from "@repo/testing/e2e";

test.describe("Account Pages", () => {
  let _authHelpers: BetterAuthTestHelpers;
  let waitUtils: WaitUtils;
  let visual: VisualTestUtils;
  let a11y: AccessibilityTestUtils;

  test.beforeEach(async ({ page }) => {
    _authHelpers = createAuthHelpers("http://localhost:3200");
    waitUtils = new WaitUtils(page);
    visual = new VisualTestUtils(page);
    a11y = new AccessibilityTestUtils(page);
  });

  test.describe("Account Dashboard", () => {
    test("should redirect to login when not authenticated", async ({
      page,
    }) => {
      await page.goto("/en/account");
      await waitUtils.forNavigation();

      // Should redirect to login page or show login form
      const currentUrl = page.url();
      if (currentUrl.includes("/login") || currentUrl.includes("/signin")) {
        await expect(page).toHaveURL(/\/(login|signin)/);
      } else {
        // Might show inline login or auth form
        const loginForm = page
          .locator("form")
          .filter({ hasText: /login|sign in/i });
        const emailInput = page.locator('input[type="email"]');

        if ((await loginForm.count()) > 0 || (await emailInput.count()) > 0) {
          expect(
            (await loginForm.count()) > 0 || (await emailInput.count()) > 0,
          ).toBeTruthy();
        }
      }
    });

    test("should load account page structure", async ({ page }) => {
      await page.goto("/en/account");
      await waitUtils.forNavigation();

      // Should have main content (even if it's a login redirect)
      const main = page.locator("main");
      await expect(main).toBeVisible();

      await expect(page).toHaveTitle(/.+/);
    });

    test("should have account navigation", async ({ page }) => {
      await page.goto("/en/account");
      await waitUtils.forNavigation();

      // Look for account navigation links (if authenticated view is shown)
      const accountLinks = [
        page.getByRole("link", { name: /profile|account/i }),
        page.getByRole("link", { name: /orders|order history/i }),
        page.getByRole("link", { name: /wishlist|favorites/i }),
        page.getByRole("link", { name: /billing|payment/i }),
        page.getByRole("link", { name: /password|security/i }),
      ];

      let hasAccountNav = false;
      for (const link of accountLinks) {
        if (await link.isVisible()) {
          hasAccountNav = true;
          break;
        }
      }

      // If we see account navigation, we're in the authenticated view
      if (hasAccountNav) {
        expect(hasAccountNav).toBeTruthy();
      }
    });

    test("should be accessible", async ({ page }) => {
      await page.goto("/en/account");
      await waitUtils.forNavigation();

      const results = await a11y.runCommonChecks();

      expect(results.criticalViolations).toHaveLength(0);
      expect(results.seriousViolations).toHaveLength(0);
    });
  });

  test.describe("Account Billing Page", () => {
    test("should load billing page", async ({ page }) => {
      await page.goto("/en/account-billing");
      await waitUtils.forNavigation();

      await expect(page).toHaveTitle(/.+/);
      await expect(page).toHaveURL(/\/account-billing/);

      const main = page.locator("main");
      await expect(main).toBeVisible();
    });

    test("should handle billing form elements", async ({ page }) => {
      await page.goto("/en/account-billing");
      await waitUtils.forNavigation();

      // Look for billing-related elements (if not redirected to login)
      const notRedirected = !page.url().includes("/login");

      if (notRedirected) {
        const billingForm = page
          .locator("form")
          .filter({ hasText: /billing|payment/i });
        const addressInput = page.locator('input[name*="address"]');
        const cardInput = page.locator('input[name*="card"]');

        // If billing form exists, test its elements
        if ((await billingForm.count()) > 0) {
          await expect(billingForm).toBeVisible();
        }

        if ((await addressInput.count()) > 0) {
          await expect(addressInput.first()).toBeVisible();
        }
      }
    });

    test("should validate required billing fields", async ({ page }) => {
      await page.goto("/en/account-billing");
      await waitUtils.forNavigation();

      const notRedirected = !page.url().includes("/login");

      if (notRedirected) {
        const submitButton = page.getByRole("button", {
          name: /save|update|submit/i,
        });

        if (
          (await submitButton.count()) > 0 &&
          (await submitButton.first().isVisible())
        ) {
          // Try to submit empty form
          await submitButton.first().click();

          // Look for validation messages
          const errorMessage = page
            .locator('[role="alert"]')
            .or(page.locator(".error"));

          await page.waitForTimeout(1000);

          if ((await errorMessage.count()) > 0) {
            const errorText = await errorMessage.first().textContent();
            expect(errorText).toBeTruthy();
          }
        }
      }
    });
  });

  test.describe("Account Password Page", () => {
    test("should load password page", async ({ page }) => {
      await page.goto("/en/account-password");
      await waitUtils.forNavigation();

      await expect(page).toHaveTitle(/.+/);
      await expect(page).toHaveURL(/\/account-password/);

      const main = page.locator("main");
      await expect(main).toBeVisible();
    });

    test("should have password change form", async ({ page }) => {
      await page.goto("/en/account-password");
      await waitUtils.forNavigation();

      const notRedirected = !page.url().includes("/login");

      if (notRedirected) {
        const passwordForm = page
          .locator("form")
          .filter({ hasText: /password|change/i });
        const currentPasswordInput = page.locator('input[name*="current"]');
        const newPasswordInput = page.locator('input[name*="new"]');

        if ((await passwordForm.count()) > 0) {
          await expect(passwordForm).toBeVisible();

          // Should have current and new password fields
          if ((await currentPasswordInput.count()) > 0) {
            await expect(currentPasswordInput.first()).toBeVisible();
          }

          if ((await newPasswordInput.count()) > 0) {
            await expect(newPasswordInput.first()).toBeVisible();
          }
        }
      }
    });

    test("should validate password requirements", async ({ page }) => {
      await page.goto("/en/account-password");
      await waitUtils.forNavigation();

      const notRedirected = !page.url().includes("/login");

      if (notRedirected) {
        const newPasswordInput = page.locator('input[name*="new"]').first();
        const submitButton = page.getByRole("button", {
          name: /change|update|save/i,
        });

        if (
          (await newPasswordInput.count()) > 0 &&
          (await submitButton.count()) > 0
        ) {
          // Fill with weak password
          await newPasswordInput.fill("123");
          await submitButton.first().click();

          // Should show password requirements
          const errorMessage = page
            .locator('[role="alert"]')
            .or(page.getByText(/password.*requirements/i));

          await page.waitForTimeout(1000);

          if ((await errorMessage.count()) > 0) {
            const errorText = await errorMessage.first().textContent();
            expect(errorText).toBeTruthy();
          }
        }
      }
    });
  });

  test.describe("Account Wishlists Page", () => {
    test("should load wishlists page", async ({ page }) => {
      await page.goto("/en/account-wishlists");
      await waitUtils.forNavigation();

      await expect(page).toHaveTitle(/.+/);
      await expect(page).toHaveURL(/\/account-wishlists/);

      const main = page.locator("main");
      await expect(main).toBeVisible();
    });

    test("should handle empty wishlist state", async ({ page }) => {
      await page.goto("/en/account-wishlists");
      await waitUtils.forNavigation();

      const notRedirected = !page.url().includes("/login");

      if (notRedirected) {
        // Look for empty state or wishlist items
        const emptyMessage = page.getByText(/empty|no items|no favorites/i);
        const wishlistItems = page
          .locator('[data-testid="wishlist-item"]')
          .or(page.locator(".wishlist-item"));

        // Should show either empty state or items
        const hasEmpty = (await emptyMessage.count()) > 0;
        const hasItems = (await wishlistItems.count()) > 0;

        expect(hasEmpty || hasItems).toBeTruthy();
      }
    });

    test("should handle wishlist item actions", async ({ page }) => {
      await page.goto("/en/account-wishlists");
      await waitUtils.forNavigation();

      const notRedirected = !page.url().includes("/login");

      if (notRedirected) {
        const removeButton = page.getByRole("button", {
          name: /remove|delete/i,
        });
        const addToCartButton = page.getByRole("button", {
          name: /add to cart/i,
