  const [selectedColor, setSelectedColor] = useState(product.colors?.[0]?.name);

  // Track product view
  useEffect(() => {
    activity.trackProductView({
      id: product.id,
      image: product.images?.[0]?.src,
      price: product.price,
      title: product.title,
      viewedAt: new Date(),
    });
