              <BagIcon className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Product Info Overlay - Scrolls over gallery */}
        <div className="relative bg-white dark:bg-neutral-900 -mt-20 rounded-t-[40px] pt-8 pb-20">
          <div className="container">
            <div className="lg:grid lg:grid-cols-2 lg:gap-16">
              {/* Left: Product Details */}
              <div className="space-y-8">
                {/* Title and Price */}
                <div>
                  <Heading>{product.title}</Heading>

                  <div className="mt-4 flex items-center gap-4">
                    <Prices className="text-2xl" price={product.price} />
                    {product.status && (
                      <ProductStatus status={product.status} />
                    )}
                  </div>

                  {/* Rating */}
                  {product.rating && (
                    <div className="mt-4 flex items-center gap-2">
                      <FiveStartIconForRate defaultPoint={product.rating} />
                      <span className="text-sm text-neutral-500">
                        {product.rating} ({product.reviewCount}{" "}
                        {dict.product?.reviews || "reviews"})
                      </span>
                    </div>
                  )}
                </div>

                {/* Description */}
                <div className="prose prose-sm dark:prose-invert">
                  <p>{product.description}</p>
                </div>

                {/* Features */}
                {product.features && (
                  <div>
                    <h3 className="text-lg font-medium mb-4">
                      {dict.product?.features || "Features"}
                    </h3>
                    <ul className="space-y-2">
                      {product.features.map(
                        (feature: string, index: number) => (
                          <li key={index} className="flex items-start gap-2">
                            <VerifyIcon className="w-5 h-5 mt-0.5 text-green-500" />
                            <span className="text-neutral-600 dark:text-neutral-400">
                              {feature}
                            </span>
                          </li>
                        ),
                      )}
                    </ul>
                  </div>
                )}
              </div>

              {/* Right: Purchase Options */}
              <div className="mt-8 lg:mt-0 space-y-6 lg:sticky lg:top-24 lg:h-fit">
                {/* Variants */}
                {product.colors && product.colors.length > 0 && (
                  <div>
                    <Label>{dict.product?.color || "Color"}</Label>
                    <div className="mt-2 flex flex-wrap gap-2">
                      {product.colors.map((color: any) => (
                        <button
                          key={color.name}
                          onClick={() => setSelectedColor(color.name)}
                          className={`w-10 h-10 rounded-full border-2 ${
                            selectedColor === color.name
                              ? "border-neutral-900 dark:border-white"
                              : "border-transparent"
                          }`}
                          style={{ backgroundColor: color.value }}
                          title={color.name}
                        />
                      ))}
                    </div>
                  </div>
                )}

                {/* Size Selection */}
                {product.sizes && product.sizes.length > 0 && (
                  <div>
                    <Label>{dict.product?.size || "Size"}</Label>
                    <div className="mt-2 flex flex-wrap gap-2">
                      {product.sizes.map((size: string) => (
                        <Button
                          key={size}
                          onClick={() => setSelectedSize(size)}
                          size="sm"
                          variant={selectedSize === size ? "filled" : "outline"}
                        >
                          {size}
                        </Button>
                      ))}
                    </div>
                  </div>
                )}

                {/* Quantity and Actions */}
                <div className="space-y-4">
                  <div className="flex items-center gap-4">
                    <Label>{dict.product?.quantity || "Quantity"}</Label>
                    <NcInputNumber
                      className="w-32"
                      defaultValue={1}
                      max={product.stock || 99}
                      min={1}
                    />
                  </div>

                  <AddToCardButton
                    className="w-full"
                    imageUrl={product.images?.[0]?.src || ""}
                    price={product.price || 0}
                    quantity={1}
                    size="lg"
                    title={product.title}
                  >
                    {dict.product?.addToCart || "Add to Cart"}
                  </AddToCardButton>

                  <LikeSaveBtnsWithFavorites
                    productId={product.id}
                    productName={product.title}
                  />
                </div>

                {/* Additional Info */}
                <div className="border-t pt-6 space-y-4">
                  <AccordionInfo
                    data={[
                      {
                        name: dict.product?.shipping || "Shipping & Returns",
                        content:
                          "Free shipping on orders over $50. Easy 30-day returns.",
                      },
                      {
                        name: dict.product?.materials || "Materials & Care",
                        content:
                          product.materials ||
                          "Premium materials. Machine washable.",
                      },
                    ]}
                  />
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Reviews Section */}
      {reviews && reviews.length > 0 && (
        <div className="container py-16">
          <Heading className="mb-8">
            {dict.product?.customerReviews || "Customer Reviews"}
          </Heading>
          <div className="grid gap-6 lg:grid-cols-2">
            {reviews.map((review: any, index: number) => (
              <ReviewItem key={index} data={review} />
            ))}
          </div>
        </div>
      )}

      {/* Related Products */}
      {relatedProducts && relatedProducts.length > 0 && (
        <div className="container py-16">
          <Heading className="mb-8">
            {dict.product?.youMayAlsoLike || "You May Also Like"}
          </Heading>
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
            {relatedProducts.map((item) => (
              <ProductCard key={item.id} data={item} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { FavoriteButton } from "@/components/FavoriteButton";
import { useGuestActions } from "@/contexts/GuestActionsContext";
import { useEffect, useState } from "react";

import { CartBtn, Link, Prices } from "@repo/design-system/mantine-ciseco";

// Define local types
interface ProductVariant {
  id: string;
  image?: string;
  name: string;
  price: number;
}

interface MinimalLayoutProps {
  dict: any;
  locale: string;
  product: any;
  relatedProducts: any[];
  reviews: any[];
}

/**
 * Minimal Layout - Clean, distraction-free design
 * Focus on essential information with maximum whitespace
 */
export function MinimalLayout({
  dict,
  locale,
  product,
  relatedProducts,
  reviews,
}: MinimalLayoutProps) {
  const { activity } = useGuestActions();
  const [selectedVariant, setSelectedVariant] = useState<ProductVariant | null>(
    null,
  );
  const [selectedImage, setSelectedImage] = useState(0);
  const [quantity, setQuantity] = useState(1);

  // Track product view
  useEffect(() => {
    activity.trackProductView({
      id: product.id,
      image: product.images?.[0]?.src,
      price: product.price,
      title: product.title,
      viewedAt: new Date(),
    });
  }, [product.id, activity, product.title, product.price, product.images]);

  const currentPrice = selectedVariant?.price || product.price;
  const images = product.images || [];

  return (
    <div className="min-h-screen bg-white dark:bg-neutral-900">
      {/* Minimal Header */}
      <div className="container py-8">
        <nav className="flex items-center justify-between">
          <Link href="/" className="text-sm text-neutral-500">
            ← {dict.common?.back || "Back"}
          </Link>
          <div className="flex items-center gap-4">
            <FavoriteButton
              productId={product.id}
              productName={product.title}
              price={currentPrice}
            />
            <CartBtn />
          </div>
        </nav>
      </div>

      {/* Main Content - Centered and Minimal */}
      <div className="container max-w-5xl mx-auto pb-20">
        <div className="grid lg:grid-cols-2 gap-16">
          {/* Left: Single Image Focus */}
          <div className="space-y-4">
            {/* Main Image */}
            <div className="aspect-square bg-neutral-100 dark:bg-neutral-800 rounded-2xl overflow-hidden">
              {images[selectedImage] && (
                <img
                  className="w-full h-full object-cover"
                  alt={images[selectedImage].alt || product.title}
                  src={images[selectedImage].src}
                />
              )}
            </div>

            {/* Thumbnails - Minimal dots */}
            {images.length > 1 && (
              <div className="flex justify-center gap-2">
                {images.map((_: any, index: number) => (
                  <button
                    key={index}
                    onClick={() => setSelectedImage(index)}
                    className={`w-2 h-2 rounded-full transition-all ${
                      selectedImage === index
                        ? "w-8 bg-neutral-900 dark:bg-white"
                        : "bg-neutral-300 dark:bg-neutral-600"
                    }`}
                    aria-label={`View image ${index + 1}`}
                  />
                ))}
              </div>
            )}
          </div>

          {/* Right: Essential Info Only */}
          <div className="flex flex-col justify-center space-y-8">
            {/* Title and Price - Large and Clear */}
            <div className="space-y-4">
              <h1 className="text-4xl font-light tracking-tight">
                {product.title}
              </h1>

              <div className="text-3xl font-light">
                <Prices className="text-inherit" price={product.price} />
              </div>
            </div>

            {/* Simple Description */}
            <p className="text-neutral-600 dark:text-neutral-400 leading-relaxed">
              {product.description}
            </p>

            {/* Minimal Variant Selection */}
            {product.variants && product.variants.length > 1 && (
              <div className="space-y-4">
                <select
                  onChange={(e) => {
                    const variant = product.variants.find(
                      (v: any) => v.id === e.target.value,
                    );
                    setSelectedVariant(variant);
                  }}
                  className="w-full px-4 py-3 bg-transparent border border-neutral-200 dark:border-neutral-700 rounded-lg focus:outline-none focus:border-neutral-900 dark:focus:border-white"
                >
                  <option value="">
                    {dict.product?.selectOption || "Select Option"}
                  </option>
                  {product.variants.map((variant: any) => (
                    <option key={variant.id} value={variant.id}>
                      {variant.name}
                    </option>
                  ))}
                </select>
              </div>
            )}

            {/* Simple Quantity and Add to Cart */}
            <div className="space-y-4">
              <div className="flex items-center gap-4">
                <label className="text-sm text-neutral-500">
                  {dict.product?.quantity || "Quantity"}
                </label>
                <div className="flex items-center border border-neutral-200 dark:border-neutral-700 rounded-lg">
                  <button
                    onClick={() => setQuantity(Math.max(1, quantity - 1))}
                    className="px-4 py-2 hover:bg-neutral-100 dark:hover:bg-neutral-800"
                  >
                    −
                  </button>
                  <span className="px-4 py-2 min-w-[3rem] text-center">
                    {quantity}
                  </span>
                  <button
                    onClick={() => setQuantity(quantity + 1)}
                    className="px-4 py-2 hover:bg-neutral-100 dark:hover:bg-neutral-800"
                  >
                    +
                  </button>
                </div>
              </div>

              <button className="w-full py-4 bg-neutral-900 dark:bg-white text-white dark:text-neutral-900 rounded-lg hover:opacity-90 transition-opacity">
                {dict.product?.addToCart || "Add to Cart"}
              </button>
            </div>

            {/* Minimal Additional Info */}
            <div className="pt-8 border-t border-neutral-200 dark:border-neutral-700 space-y-2 text-sm text-neutral-500">
              <p>
                ✓{" "}
                {dict.product?.freeShipping ||
                  "Free shipping on orders over $50"}
              </p>
              <p>✓ {dict.product?.easyReturns || "30-day easy returns"}</p>
              <p>✓ {dict.product?.securePayment || "Secure payment"}</p>
            </div>
          </div>
        </div>
      </div>

      {/* Minimal Related Products */}
      {relatedProducts && relatedProducts.length > 0 && (
        <div className="border-t border-neutral-200 dark:border-neutral-700">
          <div className="container py-16">
            <h2 className="text-2xl font-light text-center mb-12">
              {dict.product?.similarItems || "Similar Items"}
            </h2>
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-8">
              {relatedProducts.slice(0, 4).map((item) => (
                <div key={item.id} className="group cursor-pointer">
                  <div className="aspect-square bg-neutral-100 dark:bg-neutral-800 rounded-lg overflow-hidden mb-4">
                    <img
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform"
                      alt={item.title}
                      src={item.image}
                    />
                  </div>
                  <h3 className="text-sm">{item.title}</h3>
                  <p className="text-sm text-neutral-500">${item.price}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

