"use client";

import {
  useLocalStorage,
  useMap,
  useMediaQuery,
  useViewportSize,
} from "@mantine/hooks";
import { usePathname } from "next/navigation";
import {
  createContext,
  type ReactNode,
  useContext,
  useEffect,
  useMemo,
  useTransition,
} from "react";

// Simplified version without analytics

export interface GuestPreferences {
  currency: "USD" | "EUR" | "GBP";
  locale: "en" | "fr" | "es" | "pt" | "de";
  sortPreference: "featured" | "price-low" | "price-high" | "newest";
  viewMode: "grid" | "list";
}

interface ListOperations {
  add: (
    listType: string,
    itemId: string,
    metadata?: Record<string, any>,
  ) => Promise<void>;
  clear: (listType: string) => void;
  get: (listType: string) => string[];
  has: (listType: string, itemId: string) => boolean;
  remove: (listType: string, itemId: string) => Promise<void>;
  toggle: (
    listType: string,
    itemId: string,
    metadata?: Record<string, any>,
  ) => Promise<boolean>;
}

interface ActivityOperations {
  trackInteraction: (interaction: any) => void;
  trackPageView: (
    category: string,
    name?: string,
    properties?: Record<string, any>,
  ) => void;
  trackProductView: (item: any) => void;
  trackSearch: (query: string, resultsCount: number) => void;
}

interface GuestOperations {
  becomeAuthenticated: (userId: string) => Promise<void>;
  id: string;
  isAuthenticated: boolean;
}

interface PreferencesOperations {
  get: (key: string) => any;
  reset: () => void;
  set: (key: string, value: any) => void;
}

interface GuestActionsContextValue {
  activity: ActivityOperations;
  device: {
    isMobile: boolean;
    isTablet: boolean;
    isDesktop: boolean;
    viewport: { width: number; height: number };
  };
  guest: GuestOperations;
  lists: ListOperations;
  preferences: PreferencesOperations;
}

const GuestActionsContext = createContext<GuestActionsContextValue | undefined>(
  undefined,
);

const DEFAULT_PREFERENCES = {
  currency: "USD",
  locale: "en",
  sortPreference: "featured",
  viewMode: "grid",
} as const satisfies GuestPreferences;

export function GuestActionsProvider({ children }: { children: ReactNode }) {
  const pathname = usePathname();
  const [isPending, startTransition] = useTransition();

  // Guest ID management
  const [guestId] = useLocalStorage({
    defaultValue: () => `guest-${Math.random().toString(36).substring(2, 15)}`,
    key: "guest-id",
  });

  const [authenticatedUserId, setAuthenticatedUserId] = useLocalStorage({
    defaultValue: "",
    key: "authenticated-user-id",
  });

  // Device detection
  const isMobile = useMediaQuery("(max-width: 768px)");
  const isTablet = useMediaQuery("(min-width: 769px) and (max-width: 1024px)");
  const isDesktop = useMediaQuery("(min-width: 1025px)");
  const viewport = useViewportSize();

  // Preferences
  const [preferences, setPreferences] = useLocalStorage<GuestPreferences>({
    defaultValue: DEFAULT_PREFERENCES,
    key: "guest-preferences",
  });

  // Lists (favorites, wishlists, etc.)
  const lists = useMap<string, string[]>();

  // Initialize lists from localStorage
  useEffect(() => {
    const savedFavorites = localStorage.getItem("guest-favorites");
    if (savedFavorites) {
      try {
        lists.set("favorites", JSON.parse(savedFavorites));
      } catch {}
    }
  }, [lists]);

  // Save favorites to localStorage
  useEffect(() => {
    const favorites = lists.get("favorites");
    if (favorites) {
      localStorage.setItem("guest-favorites", JSON.stringify(favorites));
    }
  }, [lists]);

  // Operations
  const listOperations = useMemo<ListOperations>(
    () => ({
      add: async (
        listType: string,
        itemId: string,
        metadata?: Record<string, any>,
      ) => {
        const currentList = lists.get(listType) || [];
        if (!currentList.includes(itemId)) {
          lists.set(listType, [...currentList, itemId]);
        }
      },

      remove: async (listType: string, itemId: string) => {
        const currentList = lists.get(listType) || [];
        lists.set(
          listType,
          currentList.filter((id) => id !== itemId),
        );
      },

      toggle: async (
        listType: string,
        itemId: string,
        metadata?: Record<string, any>,
      ) => {
        const currentList = lists.get(listType) || [];
        const has = currentList.includes(itemId);

        if (has) {
          lists.set(
            listType,
            currentList.filter((id) => id !== itemId),
          );
        } else {
          lists.set(listType, [...currentList, itemId]);
        }

        return !has;
      },

      has: (listType: string, itemId: string) => {
        const currentList = lists.get(listType) || [];
        return currentList.includes(itemId);
      },

      get: (listType: string) => lists.get(listType) || [],

      clear: (listType: string) => {
        lists.set(listType, []);
      },
    }),
    [lists],
  );

  const activityOperations = useMemo<ActivityOperations>(
    () => ({
      trackPageView: (
        category: string,
        name?: string,
        properties?: Record<string, any>,
      ) => {
        // No-op
      },

      trackProductView: (item: any) => {
        // No-op
      },

      trackSearch: (query: string, resultsCount: number) => {
        // No-op
      },

      trackInteraction: (interaction: any) => {
        // No-op
      },
    }),
    [],
  );

  const preferencesOperations = useMemo<PreferencesOperations>(
    () => ({
      set: (key: string, value: any) => {
        startTransition(() => {
          setPreferences((prev) => ({ ...prev, [key]: value }));
        });
      },

      get: (key: string) => preferences[key as keyof GuestPreferences],

      reset: () => {
        startTransition(() => {
          setPreferences(DEFAULT_PREFERENCES);
        });
      },
    }),
    [preferences, setPreferences],
  );

  const guestOperations = useMemo<GuestOperations>(
    () => ({
      id: guestId(),
      becomeAuthenticated: async (userId: string) => {
        setAuthenticatedUserId(userId);
      },
      isAuthenticated: !!authenticatedUserId,
    }),
    [guestId, authenticatedUserId, setAuthenticatedUserId],
  );

  const value = useMemo<GuestActionsContextValue>(
    () => ({
      activity: activityOperations,
      device: {
        isDesktop: isDesktop ?? true,
        isMobile: isMobile ?? false,
        isTablet: isTablet ?? false,
        viewport: { width: viewport.width, height: viewport.height },
      },
      guest: guestOperations,
      lists: listOperations,
      preferences: preferencesOperations,
    }),
    [
      guestOperations,
      listOperations,
      activityOperations,
      preferencesOperations,
      isMobile,
      isTablet,
      isDesktop,
      viewport,
    ],
  );

  return (
    <GuestActionsContext.Provider value={value}>
      {children}
    </GuestActionsContext.Provider>
  );
}

export function useGuestActions() {
  const context = useContext(GuestActionsContext);
  if (!context) {
    throw new Error(
      "useGuestActions must be used within a GuestActionsProvider",
    );
  }
  return context;
}

"use client";

import { useGuestActions } from "@/contexts/GuestActionsContext";
import { useEffect, useState } from "react";

export function useGuestFavorites() {
  const { lists } = useGuestActions();
  const [favoriteIds, setFavoriteIds] = useState<string[]>([]);

  useEffect(() => {
    // Get favorites from localStorage
    const stored = localStorage.getItem("guest-lists-favorites");
    if (stored) {
      try {
        const parsed = JSON.parse(stored);
        setFavoriteIds(Object.keys(parsed));
      } catch (_e) {
        setFavoriteIds([]);
      }
    }
  }, []);

  return {
    addFavorite: (id: string, metadata?: any) =>
      lists.add("favorites", id, metadata),
    favoriteCount: favoriteIds.length,
    favorites: new Set(favoriteIds),
    isFavorite: (id: string) => lists.has("favorites", id),
    removeFavorite: (id: string) => lists.remove("favorites", id),
    toggleFavorite: (id: string, metadata?: any) =>
      lists.toggle("favorites", id),
  };
}

export function useProductFavorite(productId: string, metadata?: any) {
  const { lists } = useGuestActions();

  return {
    addToFavorites: () => lists.add("favorites", productId, metadata),
    isFavorite: lists.has("favorites", productId),
    removeFromFavorites: () => lists.remove("favorites", productId),
    toggleFavorite: () => lists.toggle("favorites", productId),
  };
}

"use client";

import { useGuestActions } from "@/contexts/GuestActionsContext";

// Convenience hook for responsive behavior
export function useResponsive() {
  const { device } = useGuestActions();
  return device;
}

// Hook for responsive grid layouts
export function useResponsiveGrid() {
  const { device } = useGuestActions();
  const { width } = device.viewport;

  const columns = device.isMobile
    ? 1
    : device.isTablet
      ? 2
      : device.isDesktop
        ? 4
        : 3;
  const gap = device.isMobile ? 16 : device.isTablet ? 20 : 24;

  // Calculate items per page based on viewport
  const itemsPerPage =
    columns * (device.isMobile ? 6 : device.isTablet ? 4 : 3);

  return {
    gridClass: `grid grid-cols-${columns} gap-${gap}px`,
    columns,
    gap,
    itemsPerPage,
  };
}

// Hook for responsive product loading
export function useResponsiveProductLoad() {
  const { device, preferences } = useGuestActions();
  const { viewport } = device;

  // Adjust based on viewport and view mode
  const isGridView = preferences.get("viewMode") === "grid";

  const productsPerRow = device.isMobile
    ? 1
    : device.isTablet
      ? isGridView
        ? 2
        : 1
      : isGridView
        ? 4
        : 2;

  const initialLoadCount = productsPerRow * 3; // Load 3 rows initially
  const loadMoreCount = productsPerRow * 2; // Load 2 more rows on scroll

  return {
    isGridView,
    initialLoadCount,
    loadMoreCount,
    productsPerRow,
  };
}

// Hook for responsive image sizes
export function useResponsiveImage() {
  const { device } = useGuestActions();

  const getImageSize = (base: number) => {
    if (device.isMobile) return base * 0.75;
    if (device.isTablet) return base * 0.85;
    return base;
  };

  const getSizes = () => {
    if (device.isMobile) return "100vw";
    if (device.isTablet) return "50vw";
    return "25vw";
  };

  return {
    getImageSize,
    getSizes,
    priority: device.isMobile ? false : true,
    quality: device.isMobile ? 75 : 90,
  };
}

